INSERT INTO `lesson` (`id`, `page_id`, `title`, `name`, `content`) VALUES
(1, 1, 'HTML & CSS: Design and Build Websites', 'Глава 1: Структура', '<p>Ежедневно мы сталкиваемся с различными типами документов. Газеты, заявления на выдачу паспорта, каталоги. Этот список можно продолжать до бесконечности.</p>\n        \n        <p>Многие веб-страницы функционируют как электронные версии вышеперечисленных документов. Например газеты публикуют одни и те же репортажи как на бумаге, так и на собственных сайтах; с помощью Всемирной паутины вы также можете написать заявление на получение паспорта; интернет-магазины содержат онлайн-версии каталогов и средства электронной коммерции.</p>\n        \n        <p>Структура важна для всех типов документов: она помогает читателям понять информацию, которую вы пытаетесь до них донести, а также способствует более простому переходу между частями документов. Таким образом, чтобы научиться создавать веб-страницы, важно понять, как правильно структурировать документы. В этой главе вы:</p>\n\n        <p>увидите, как язык HTML описывает структуру веб-страницы; узнаете, как нужно вставлять в документ теги и элементы; сверстаете свою первую веб-страницу.</p>\n        '),
(2, 2, 'CSS: The Missing Manual', 'Глава 1: Структура', '<p>Ежедневно мы сталкиваемся с различными типами документов. Газеты, заявления на выдачу паспорта, каталоги. Этот список можно продолжать до бесконечности.</p>\n        \n        <p>Многие веб-страницы функционируют как электронные версии вышеперечисленных документов. Например газеты публикуют одни и те же репортажи как на бумаге, так и на собственных сайтах; с помощью Всемирной паутины вы также можете написать заявление на получение паспорта; интернет-магазины содержат онлайн-версии каталогов и средства электронной коммерции.</p>\n        \n        <p>Структура важна для всех типов документов: она помогает читателям понять информацию, которую вы пытаетесь до них донести, а также способствует более простому переходу между частями документов. Таким образом, чтобы научиться создавать веб-страницы, важно понять, как правильно структурировать документы. В этой главе вы:</p>\n\n        <p>увидите, как язык HTML описывает структуру веб-страницы; узнаете, как нужно вставлять в документ теги и элементы; сверстаете свою первую веб-страницу.</p>\n        '),
(3, 1, 'HTML & CSS: Design and Build Websites', 'Глава 2: Структура', '<p>Ежедневно мы сталкиваемся с различными типами документов. Газеты, заявления на выдачу паспорта, каталоги. Этот список можно продолжать до бесконечности.</p>\n        \n        <p>Многие веб-страницы функционируют как электронные версии вышеперечисленных документов. Например газеты публикуют одни и те же репортажи как на бумаге, так и на собственных сайтах; с помощью Всемирной паутины вы также можете написать заявление на получение паспорта; интернет-магазины содержат онлайн-версии каталогов и средства электронной коммерции.</p>\n        \n        <p>Структура важна для всех типов документов: она помогает читателям понять информацию, которую вы пытаетесь до них донести, а также способствует более простому переходу между частями документов. Таким образом, чтобы научиться создавать веб-страницы, важно понять, как правильно структурировать документы. В этой главе вы:</p>\n\n        <p>увидите, как язык HTML описывает структуру веб-страницы; узнаете, как нужно вставлять в документ теги и элементы; сверстаете свою первую веб-страницу.</p>\n        '),
(5, 5, 'Современный учебник JavaScript', 'Введение в JavaScript', '<p>JavaScript изначально был создан, чтобы сделать веб-страницы живыми. Программы на этом языке называются скриптами.</p><p>Сегодня JavaScript может выполняться не только в браузере, но и на сервере.</p>'),
(6, 7, 'Современный учебник JavaScript', 'Переменные', '<p>Переменная — это \"именованное хранилище\" для данных. Для создания переменной используйте ключевое слово let или const.</p>'),
(7, 13, 'Современный учебник JavaScript', 'Введение в JavaScript', '<p>Здесь будет текст про введение в JS...</p>'),
(8, 14, 'Современный учебник JavaScript', 'Справочники и спецификации', '<p>Описание спецификаций...</p>'),
(9, 15, 'Современный учебник JavaScript', 'Редакторы кода', '<p>Обзор редакторов...</p>'),
(10, 16, 'Современный учебник JavaScript', 'Консоль разработчика', '<p>Как работать с консолью...</p>'),
(11, 17, 'Современный учебник JavaScript', 'Привет, мир!', '<p>Первая программа...</p>'),
(12, 18, 'Современный учебник JavaScript', 'Структура кода', '<p>Инструкции и точки с запятой...</p>'),
(13, 19, 'Современный учебник JavaScript', 'Строгий режим — \"use strict\"', '<p>Описание строгого режима...</p>'),
(14, 20, 'Современный учебник JavaScript', 'Переменные', '<p>let, const, var...</p>'),
(15, 21, 'Современный учебник JavaScript', 'Типы данных', '<p>Числа, строки и т.д...</p>'),
(16, 22, 'Современный учебник JavaScript', 'Преобразование типов', '<p>Явное и неявное преобразование...</p>'),
(17, 23, 'Современный учебник JavaScript', 'Операторы', '<p>Математические операторы...</p>'),
(18, 24, 'Современный учебник JavaScript', 'Операторы сравнения', '<p>==, ===, >, <...</p>'),
(19, 25, 'Современный учебник JavaScript', 'Взаимодействие: alert, prompt, confirm', '<p>Модальные окна браузера...</p>'),
(20, 26, 'Современный учебник JavaScript', 'Условные операторы: if, \"?\"', '<p>Ветвление кода...</p>'),
(21, 27, 'Современный учебник JavaScript', 'Логические операторы', '<p>||, &&, !...</p>'),
(22, 28, 'Современный учебник JavaScript', 'Циклы while и for', '<p>Повторение действий...</p>'),
(23, 29, 'Современный учебник JavaScript', 'Конструкция \"switch\"', '<p>Выбор из множества вариантов...</p>'),
(24, 30, 'Современный учебник JavaScript', 'Функции', '<p>Объявление функций...</p>'),
(25, 31, 'Современный учебник JavaScript', 'Function Expression', '<p>Выражения-функции...</p>'),
(26, 32, 'Современный учебник JavaScript', 'Функции-стрелки, основы', '<p>Синтаксис стрелочных функций...</p>'),
(27, 33, 'Современный учебник JavaScript', 'Особенности JavaScript', '<p>Уникальные черты языка...</p>'),
(28, 34, 'Современный учебник JavaScript', 'Качество кода', '<p>Как писать чистый код...</p>'),
(29, 35, 'Современный учебник JavaScript', 'Отладка в браузере Chrome', '<p>Контент для урока: Отладка в браузере Chrome. Здесь будет подробное описание темы.</p>'),
(30, 36, 'Современный учебник JavaScript', 'Советы по стилю кода', '<p>Контент для урока: Советы по стилю кода. Здесь будет подробное описание темы.</p>'),
