INSERT INTO `reply` (`id`, `body`, `column2`, `author_id`, `replyable_id`, `datetime`) VALUES
(1, 'Придерживаться общечеловеческих норм общения и размещать сообщения, отвечающие тематике.', '', 1, 12, '2026-06-18 09:35:43'),
(2, 'Система управления контентом\r\n\r\nЦель\r\n\r\nНаписать cms на принципах mvc (модель представление контроллер)\r\nна базе сайта https://stores2.q-pax.ru/\r\n\r\n\r\nУчебник\r\nhttps://www.programulin.ru/\r\n\r\n\r\nПлан\r\n\r\n1 нед Разобраться в устройстве cms\r\n2 нед Добавить сайту форум\r\n3 нед Разделить модули на публичные, кабинеты и административные\r\n4 нед Переместить публичные модули в папку /public/\r\n5 нед написать модуль редактирования модулей', '', 1, 18, '2026-06-18 09:35:43'),
(3, 'Задача (на 5 недель)\r\n\r\n\r\nРазобраться в устройстве:\r\n\r\n-  одной точки входа. посмотреть файл .htaccess\r\n-  принципах mvc\r\n-  Изучить структуру БД проекта\r\n-  псмотреть устройство index файла\r\n-  Разобраться в кодах модулей core и login\r\n\r\n\r\nДобавить сайту форум:\r\n\r\n-  по аналогии с модулем товаров.\r\n-  добавить таблицу для записей с картинками.\r\n-  Добавить таблицу веток форума (категории или темы).\r\n-  Предусмотреть возможность вложения веток форума друг в друга.\r\n-  Добавить форму через которую можно добавлять записи. метод add_reply\r\n-  Создать модуль выводящий все ветки форума и сообщения выбранной ветки.\r\n-  -  методы all_categories и branch\r\n\r\n\r\nРазделить модули на публичные, кабинеты и административные\r\n\r\n-  в таблицу модулей добавить поле admin (значения 0 1 2 или public private admin)\r\n-  не административные модули при добавлении должны быть доступны неавторизованному пользователю без необходимости правок модуля core\r\n-  административные модули должны находится в папке /module/admin/ + module_name\r\n-  модули кабинетов должны находится в папке /module/private/\r\n-  Кабинеты (private) модули - должны быть доступны только зарегистрированным пользователям с правами manager.\r\n-  Поместить модуль manager значением для роли manager.\r\n-  Добавить простой административный модуль - доступный только пользователям с административными правами.\r\n\r\nПереместить публичные модули в папку /public/ с сохранением работоспособности сайта\r\n-  для этого надо будет поменять модуль core\r\n\r\n\r\nДобавить административный модуль редактирования модулей\r\n\r\n-  модуль должен принадлежать к числу административных\r\n-  должен позволять создавать новые модули и привязывать к ним таблицу\r\n-  заносить данные о новом модуле в БД - устанавливать уровнь доступа к нему\r\n-  в зависимости от уровня доступа модуля - создавать для него каталог в соответствующем каталоге.\r\n-  В каталог модуля записывать файлы controller view\r\n-  -  с минимально необходимым функционалом для отображения информации из привязанной таблицы', '', 1, 18, '2026-06-18 09:35:43'),
(4, '1я Неделя\r\n\r\nТеория\r\nразделы php: Начало Другие операторы Условия Массивы\r\n\r\nРазобраться в устройстве:\r\n- организации одной точки входа в приложение - посмотреть файл .htaccess\r\nобратить внимание на правило перенаправления запросов\r\n- псмотреть устройство index файла\r\n- принципах mvc - посмотреть устройство модулей market и managment\r\n\r\n- Изучить структуру БД проекта (какие таблицы за что отвечают)\r\n- Разобраться в кодах модулей core и login\r\n- найти части кода, которые отвечает за определение доступных пользователю модулей\r\n\r\nДобавить\r\n- в таблицу модулей моле private (значения 2, 1 или 0)\r\n- в модуле main сделать выборки - всех модулей private=0 и отдельно всех модулей private=1, результаты выборок вывести на экран', '', 1, 18, '2026-06-18 09:35:43'),
(5, ' Жилые комплексы\r\n\r\nЦель\r\n\r\nСоздать сайт с возможностью посмотреть существующую карту районов и жилых комплексов.\r\nПосмотреть планировки в жилом комплексе\r\nВозможностью для жильцов подключиться к информационному пространству добрососедства в своём жилом комплексе\r\nУ совета дома или главного по дому должна быть возможность модерации сообщества - исключение торговых агентов не проживающих в данном комплексе.\r\nс возможностью для жильцов обмениваться товарами и услугами.\r\nВозможностью социума давать местному бизнесу обратную связь, улучшая качество товаров и услуг.\r\n', '', 1, 19, '2026-06-18 09:35:43'),
(6, 'Учебник\r\nhttps://www.programulin.ru/\r\n\r\nОбщий план на 5 недель\r\n\r\n1 нед\r\nсоздать структуру БД\r\nнаполнить таблицы данными\r\nСоздать общий шаблон header + menu + footer для всех страниц\r\nсоздать структуру страниц для вывода списков: районов города, микрорайонов, жилых комплексов (кварталов) + магазины микрорайона.\r\n- Создать файловую структуру проекта: каталоги с файлами обработки запросов от форм,\r\n    а также папки js css image upload\r\n- Создание html-контейнеров 3х типов: list_vertical, list_horizont, list_tile\r\n\r\n2 нед\r\nПрикрепить в шапку логотип проекта.\r\nДобавить квартире статус перечисляемого типа: ремонт, сдаётся, жилая.\r\nДобавить квартире свойство: номер авто владельца - не отображать публично.\r\nНайти макет сайта посвящённого строительству, взять оттуда разметку и стили - применить к проекту, там где это уместно.\r\nсделать страницу вывода домов в квартале\r\n - небольшими изображениями домов сверху, либо схемы\r\nвывести на всех основных страницах информацию из БД\r\nСделать формы регистрации и авторизации, \r\nВёрстку форм прикрепления владельца к квартире, добавления товара, добавления услуги.\r\nНаписать обработчики форм.\r\nДобавить роли: пользователь, член совета дома, менеджер магазина, администратор.\r\nСверстать страницу развёртки дома:\r\n - крупное фото, план и прозрачная сетка квартир на фоне фото, при наведении на дом, развёртку сделать менее прозрачной более яркой.\r\nВ БД должны быть таблицы товаров, предоставляемые и необходимые услуги - это 2 таблицы\r\nпривязываемые к квартире. Содержат id title value dimension price description flat_id image\r\n\r\n3 нед\r\nНа страницу развёртки дома по параметру home_id вывести данные дома из БД (крупное фото дома, поэтажный план, в сетку квартир вывести данные из БД)\r\nНаписать обработчик формы Привязки пользователей к квартирам.\r\nСтраница редактирования квартиры - заполняет пользователь.\r\nВозможность разместить: 3 товара, услугу, потребность - товар или услуга.\r\nПросмотреть список товаров и услуг дома может любой зарегистрированный пользователь из того же жилого комплекса. \r\n\r\n4 нед\r\nСовету дома\r\nпредоставить доступ к просмотру и редактированию дополнительной информации: по квартирам и в целом по дому,\r\nвозможность создавать у дома дополнительные ветки форума.\r\nЛК - администратора для управления информацией по комплексам и районам.\r\nнапример загрузка картинок домов и т.д.\r\n- Создание js обработчиков для всех форм\r\n- добавление комментариев на форум для всех авторизованных пользователей, принадлежащих этому дому\r\nНаписать php обработчики всех форм\r\n\r\n5 нед\r\nРазместить на странице республики и города контурную карту районов.\r\nЗа домом закрепляются ветки форума - управление доступом: для всего микрорайона, для квартала, для дома.\r\nПо дому выводить дополнительную информацию - интегрально предоставляемые и требуемые услуги жильцов, список товаров.\r\n- Создание пагинатора для товаров и услуг.', '', 1, 19, '2026-06-18 09:35:43'),
(7, 'Задача\r\n\r\nПлощадка должна обрабатывать несколько групп домов, как отдельные замкнутые системы.\r\n\r\nНаписать форум + внутренний магазин обмена, где жильцы одной группы домов могут выставлять на продажу товары и услуги с фото и описанием.\r\n\r\nУ сайта есть публичная часть, и закрытая\r\nНа публичной части размещается районированная карта города и формы регистрации и авторизации.\r\n\r\nЗакрытая часть для авторизованных пользователей состоит из Личного кабинета, страницы настроек профиля. Есть три типа личных кабинетов: Собственник, Представитель совета дома, Администратор.\r\n\r\nВ закрытой части у каждого комплекса есть: форум с ветками администрируемые советом дома, малая карта домов, поквартирная развёртка домов с поэтажным планом.\r\n\r\nмагазин товаров и услуг с категориями. Категории администрирует совет дома.\r\nСтраница со списком услуг, страница редактирования услуги, любой авторизованный пользователь может выставить свою услугу.\r\nСтраница добавления и редактирования товара. Любой авторизованный пользователь может управлять своими услугами.\r\n\r\nУ совета дома есть доступ к дополнительным скрытым свойствам объектов домов (квартир) - которые они сами заполняют.\r\n\r\nАдминистратор не ограничен одним комплексом домов.\r\nУ администратора есть доступ к системным настройкам относящимся ко всей системе в целом.', '', 1, 19, '2026-06-18 09:35:43'),
(8, '1я неделя\r\n\r\ncomplex\r\nосновы js теория\r\nphp: Начало Другие операторы Условия\r\n_____\r\nСоздание базы данных:\r\n- Описание предметной области в сущностях и свойствах\r\n- графическое моделирование базы данных со связями между таблицами\r\n- - таблицы, свойства, типы свойств связи между таблицами.\r\n- создание структуры базы данных в СУБД\r\nполя регионов, городов, районов и ЖК - id, type_area, name, description, image, css_contur, category_id, people, link\r\nДомов - id, name, address, plan, image, css_contur, material, zhk_id, compas\r\nквартиры - id, num, floor, home_id, plan, num_room, price, square, balkon\r\n- Наполнение таблиц первичными данными', '', 1, 19, '2026-06-18 09:35:43'),
(9, 'Создание тематического магазина\r\n\r\n\r\nЦель\r\n\r\nнаписать онлайн магазин\r\nс возможностью регистрации и авторизации пользователей,\r\nдвухуровневой системой категорий товаров и товарами\r\nсо страницами корзины, заказов\r\nс блоком карусели на главной странице\r\nстраницы новостей с комментариями\r\nвсе страницы должны быть оформлены в едином стиле\r\n-  Должно быть общее меню сайта на каждой странице\r\n\r\n\r\nПлан\r\n\r\n1 нед Архитектура проекта\r\n2 нед Вёрстка\r\n3 нед Бэкенд\r\n4 нед Фронтенд\r\n5 нед Администрирование', '', 1, 21, '2026-06-18 09:35:43'),
(10, 'План развёрнуто\r\n\r\n1 нед Архитектура проекта\r\n-  Создание и наполнение БД\r\n-  Создание файловой структуры\r\n-  Создание шаблона страниц\r\n-  Создание контейнеров\r\n\r\n2 нед Вёрстка\r\n-  Создание блоков контента\r\n-  Визуальная стилизация блоков\r\n-  Наполнение страниц блоками информации\r\n-  Создание форм\r\n-  -  категорий, товаров, новостей, баннеров\r\n-  Кнопки покупки\r\n-  Корзина с товарами\r\n\r\n3 нед Вывод информации с бэкенда\r\n-  Вывод списковой информации\r\n-  Вывод детальной информации\r\n-  скрипт создания корзины\r\n-  добавление товара в корзину\r\n-  скрипт перевода корзины в заказ\r\n\r\n4 нед Фронтенд (взаимодействие клиент-сервер)\r\n-  Создание пагинатора\r\n-  Создание js обработчиков для всех форм\r\n-  авторизация, регистрация\r\n-  добавление товара в корзину\r\n-  изменение корзины\r\n-  оформление заказа\r\n-  добавление комментариев\r\n-  добавление и редактирование остальных сущностей\r\n\r\n5 нед Административная часть сайта\r\n-  скрипты добавления и редактирования записей БД\r\n-  Отладка и рефакторинг проекта', '', 1, 21, '2026-06-18 09:35:43'),
(11, 'Задача\r\n\r\nСоздание базы данных:\r\n\r\n-  Описание предметной области в сущностях и свойствах\r\n-  графическое моделирование базы данных со связями между таблицами\r\n-  -  таблицы, свойства, типы свойств связи между таблицами.\r\n-  создание структуры базы данных в СУБД\r\n-  Наполнение таблиц первичными данными', '', 1, 21, '2026-06-18 09:35:43'),
(12, 'создание файловой архитектуры проекта\r\n\r\n-  файл меню сайта - ссылки на страницы сайта:\r\n-  -  категории товаров верхнего уровня + новостную страницу\r\n-  индексный файл выбора категорий товаров\r\n-  файл списка товаров одной категории\r\n-  файл детального просмотра товара\r\n-  файл ядра - подключения к БД\r\n-  страница корзины\r\n-  оформление заказа доставки и оплаты\r\n-  страница личного кабинета пользователя с архивом всех заказов и их статусом\r\n-  страница кабинета должна быть доступна только авторизоавнным пользователям, неавторизованных перебрасывать на страницу авторизации\r\n-  файл списка новостей\r\n-  файл детальной новости', '', 1, 21, '2026-06-18 09:35:43'),
(13, '-  создать каталоги:\r\n\r\n-  -  js - для всех скриптов\r\n-  -  css - все стили вёрстки\r\n-  -  image - все картинки шаблона\r\n-  -  upload - для загрузки всех файлов создаваемых объектов\r\n-  -  request - скрипты обрабатывающие ajax запросы от браузера\r\n-  -  -  работа с пользователями login logout register\r\n-  -  -  работа с товарами и категориями add_cart edit_goods edit_category\r\n-  -  -  работа с новостями и баннерами edit_news edit_banner\r\n-  -  template - папка c файлами head header footer\r\n-  -  admin - страницы управления контентом:\r\n-  -  -  категорий, товаров, пользователей, баннеров, новостей, заказов', '', 1, 21, '2026-06-18 09:35:43'),
(14, 'структура html документа по блокам\r\n\r\nСоздание шаблона страниц\r\n-  head - подключающий файлы и метаинформацию документа\r\n-  header - находится в верхней части содержит:\r\n-  -  логотип, название компании, контактные телефоны,\r\n-  -  ссылку на форму авторизации или аватар + ФИО + ссылка на личный кабинет + \r\n-  -  выход\r\n-  меню сайта\r\n-  footer - находится в нижней части экрана\r\n-  -  контактная информация, ссылки на соц сети, копирайт', '', 1, 21, '2026-06-18 09:35:43'),
(15, '-  Внутренние блоки обёртки content или wrapper\r\n\r\n-  -  баннер с каруселью картинок\r\n-  -  Заголовок текущей страницы\r\n-  -  Контейнеры\r\n-  -  -  контейнер с множеством блоков плиткой\r\n-  -  -  контейнер Вертикальный\r\n-  -  -  контейнер горизонтальный\r\n-  -  дата новости\r\n-  -  форма\r\n-  -  картинка + текст\r\n-  -  табы + внутренние блоки с информацией\r\n-  -  Кнопки покупки\r\n-  -  Корзина с товарами\r\n-  -  запись комментария: дата пользователь текст\r\n-  -  пагинатор\r\n\r\n-  Стилизация каждого визуального блока\r\n-  -  задание осей flex\r\n-  -  выравнивание отступами\r\n\r\n-  Медиа запросы стилей для адаптивной вёрстки каждого блока (десктоп, планшет, -  мобильный вариант)\r\n\r\n-  Наполнение страниц блоками информации', '', 1, 21, '2026-06-18 09:35:43'),
(16, 'Скрипты вывода информации из БД\r\n\r\n-  Выборка из БД\r\n-  разбор результата выборки\r\n-  -  Вывести циклами списковую информацию\r\n-  -  Вывести через условные операторы детальную информацию\r\n-  -  сформировать селекты для форм\r\n-  -  наполнить формы редактирования\r\n-  Добавление фильтров\r\n-  Создание пагинатора (бесконечного)', '', 1, 21, '2026-06-18 09:35:43'),
(17, 'обработчики на javascript для всех форм или для каждой отдельной формы\r\n\r\n-  найти форму - повесить на неё событие\r\n-  добавить обработчик собирающий информацию и отправляющий на скрипт из папки request\r\n-  получить и обработать ответ:\r\n-  -  проверить и разобрать json\r\n-  -  вывести ошибки\r\n-  -  оповестить о результате\r\n-  -  добавить результат к блоку', '', 1, 21, '2026-06-18 09:35:43'),
(18, 'Скрипты добавления и редактирования объектов\r\n\r\n-  Получение данных $_POST\r\n-  Валидация полученных данных\r\n-  Создание запроса INSERT\r\n-  Создание запросов на UPDATE\r\n-  защита от xss-атак - подготовка запросов\r\n-  Запись переданных файлов в upload $_FILE\r\n-  Логирование ошибок\r\n-  Выовод результата в ответ на запрос', '', 1, 21, '2026-06-18 09:35:43'),
(19, '1я Неделя\r\n\r\nосновы js теория\r\nphp: Начало Другие операторы Условия\r\n_____\r\nАрхитектура проекта (по дням)\r\n- Создание и наполнение БД\r\n(Тип магазина, текстовое описание сущностей - названия таблиц\r\nсхема с https://nosqldbm.ru/ и таблицы в myadmin)\r\n- Создание файловой структуры\r\n- Создание шаблона страниц\r\n- Создание контейнеров flex\r\nПринципы вёрстки на flexbox:\r\nhttps://itchief.ru/html-and-css/flexbox', '', 1, 21, '2026-06-18 09:35:43'),
(20, 'Оцифровка карт\r\n\r\nЦель\r\nCоздать приложение позволяющее быстро оцифровать карту контурными объектами.\r\nУ одного контурного объекта может быть несколько независимых контуров.\r\nКонтуры должны быть заданы в фиксированных плоских экранных css координатах.', '', 1, 22, '2026-06-18 09:35:43'),
(21, 'План\r\n\r\n1 нед\r\nсоздание слоёв визуального и логического\r\nпересчёт координат географических и экранных\r\nдействие клика - выставление точки\r\nформировать массив точек - limit количества (при достижении 500 не ставить больше)\r\nзамыкание по экранным координатам при заданном дельта\r\nправый клик по точке - удаление точки\r\n\r\n2 нед\r\nстек действий - действие представлять как координату тип действия, объект над которым выполнено действие.\r\n\r\nотмена ctrl+z - отменить последнее действие\r\nзамыкание по экранным координатам при заданном дельта\r\nenter - замкнуть контур и сохранить css контур\r\nотобразить без карты-подложки\r\nonfocus - подсветить контур\r\n\r\nперетаскивание и масштабирование - пересчёт видимых точек\r\nизменить рисовку на контурном слое после перемещений.\r\n\r\n3 нед\r\nполучить масштаб и координаты - состояние карты подложки\r\ncntrl+click - взять ближайшую точку другого контура\r\nвыделить контур переименовать, задать свойства\r\ndel - удалить активный контур\r\nпересчёт координат географических и экранных - проверить на большом масштабе после перемещения карты по вертикали\r\n\r\n4 нед\r\nвыделить группу контуров\r\nпостроить новый контур по внешним точкам группы\r\nвнешние - пренадлежат 1 контуру\r\nлибо принадлежность к контурам меньше количества соседних точек по всем контурам которым принадлежит\r\n\r\n5 нед\r\nОтладка, рефакторинг\r\nс помощью инструмента оцифровать карты районов удмуртии и районов Ижевска', '', 1, 22, '2026-06-18 09:35:43'),
(22, 'Задача\r\n\r\nИнструмент состоит из двух наложенных друг на друга слоёв\r\n\r\nДолжна быть кнопка или селектор перехода между слоями\r\nна первом слое отображается масштабируемая яндекс карта. Карту можно перемещать выбирая удобное положение масштаб и тип отображения.\r\nВторой слой используется для рисования - при перемещении первого слоя, объекты второго слоя должны перемещаться аналогично. Этот слой должен быть полупрозрачным.\r\n\r\nНа втором слое должны быть реализованы действия:\r\nпересчёт координат при перемещении карты-подложки. Поставить точку. Формирование массива точек контура. Соединить новую точку с предыдущей линией. Проверить замкнутось контура. Замкнуть контур. Завершить создание контуров объекта. проверка limit точек в контуре. проверить дельта расстояния последней точки от начальной - если меньше заданного - замкнуть контур.\r\nУдалить точку. стек действий. отменить действие. Перевести контур в css стили. Сохранить css файл.\r\n\r\nУбрать подложку. Подсветить замкнутые контуры объекта при наведении. Выделить объект с контуром. Отобразить название и свойства выбранного контурного объекта. Изменить свойства выделенного контурного объекта. Получение состояния карты подложки: координаты и масштаб. Масштабирование.\r\n\r\nУдалить контур. Удалить объект. Выделить группу контуров. Проверить точку в группе контуров на внутренность. Объединить группу контуров в один контур. Добавить объекту новый контур. Получить ближайшую точку другого контура.\r\n\r\nПример:\r\nhttps://energy.q-pax.ru/map', '', 1, 22, '2026-06-18 09:35:43'),
(23, '1я неделя\r\n\r\nосновы js теория\r\njs - функции и лямда-функции, объекты\r\nВведение в браузерные события\r\nПочитать об объекте канвы (canvas)\r\n_____\r\nсоздать 2 слоя - на нижнем яндекс карта\r\nверхний слой - прозрачный пустой слой канвы\r\nРазместить слои друг над другом\r\nПовесить обработчик клика на пустой слой - выводить в консоль координаты мыши во время клика\r\nОтрисовать точку на верхнем слое\r\nсделать кнопку убирающую/возвращающую верхний слой\r\nКогда верхнего слоя нет - должно быть доступно управление яндекс картой.', '', 1, 22, '2026-06-18 09:35:43'),
(24, 'Разработка модулей на js\r\n\r\nЦель\r\n\r\nРазработка модулей состоящих из изолированного кода.\r\nКоторые можно подключать к веб приложению увеличивая его функционал.', '', 1, 23, '2026-06-18 09:35:43'),
(25, 'План\r\n\r\n1 нед\r\nСоздать модули типов объектов которые можно подключить к приложению.\r\nМодули содержат название и версию.\r\nМогут возвращать список добавляемых объектов, или подробное описание одного из этих объектов с базовыми характеристиками.\r\nbuild - здания, являются контейнерами для юнитов и мебели, имеют принадлежность к фракции, дополнительный функционал\r\nenviroment - территории\r\nfraction - фракции или династии\r\nunit - юниты\r\n---\r\nobjects - предметы инвентаря, должны разделяться по типам\r\nfurniture - мебель, должна являться контейнером для предметов\r\ntransport - контейнеры для юнитов или объектов, способные для передвижения.\r\n\r\nреализовать демонстрацию этих модулей и их базовых методов кодом в файле main.js\r\n\r\n2 нед\r\nреализовать модуль\r\nsystem - должен сохранять и загружать файлы\r\nотправлять данные на сервер и обрабатывать ответ от сервера асинхронно\r\n\r\n3 нед\r\nнаписать модули\r\nscene - матрица территорий и расположенных на них объектов\r\nmap - пиксельное отображение сцены на канве с режимами объектов\r\nmenu_comand\r\n\r\n4 нед\r\nнаписать модули\r\nengine\r\ncamera\r\nscreen\r\n\r\n5 нед\r\nbuild_factory\r\nbuild_interface', '', 1, 23, '2026-06-18 09:35:43'),
(26, 'Задача\r\n\r\nРазработать приложение состоящее из изолированного кода модулей:\r\nобщей сцены, миникарты, камеры, экрана, модальные окна сообщений.\r\nТак чтобы заменяя методы или целый модуль можно было переходить\r\nк разным проекциям, из 2д в 3д и т.д\r\nДанные должны браться из таблиц сервера БД\r\n\r\n\r\nЧто должно работать в модулях\r\n\r\nсцена - хранение данных обо всех объектах\r\nвозможность подключать и использовать наборы разных объектов.\r\nкамера - выделяет кусок сцены и передаёт его другим модулям. Должна подстраиваться под изометрию.\r\n\r\nНе должна выходить за рамки сцены при прямой проекции.\r\nминикарта - должна схематично отображать фон, объекты,\r\nцветовая схема-принадлежность объектов, изменяемые режимы карты. (физика социум политика экономика и т.д.)\r\n\r\nДолжна отображать положение камеры(камер), и передавать управление камере для изменения положения.\r\n\r\nэкран - отображение тайлов фона и объектов. В несколько слоёв.\r\nПеремещение объектов не должно затирать фон. Слоёв должно быть 3.\r\nмодальные окна - выводить сообщения, скроллируемый текст + картинка + кнопка.\r\n\r\nПерехватывать все клики по экрану и не давать управления пока открыто окно. (только закрытие, листание и кнопка продолжить, либо 2 кнопки - согласия и отмены, либо поле ввода и 2 кнопки)', '', 1, 23, '2026-06-18 09:35:43'),
(27, 'Примеры реализации обёрток для модулей\r\n\r\nчерез замыкания прототипов\r\nfunction createSystem(options) {\r\nlet name, version, self;\r\nfunction System(options) {\r\n}\r\n}\r\n\r\nтот же подход реализующий синглтон\r\nlet buildProto = (function() {\r\nfunction Build(options) {\r\n}\r\n})();\r\n\r\nлибо на замыкании класса\r\nlet intellect = (function() {\r\nclass Intellect {\r\n}\r\nreturn new Intellect();\r\n})();\r\n\r\nлибо на самом классе:\r\nclass Intellect {\r\n}\r\n\r\nлибо на замыкании функции\r\nlet enviromentType = (function() {\r\nreturn function(params) {\r\n...\r\n}\r\n})();', '', 1, 23, '2026-06-18 09:35:43'),
(28, '1я Неделя\r\n\r\nосновы js теория\r\njs - функции и лямда-функции, объекты\r\nКласс: базовый синтаксис\r\nПрототипное наследование\r\n_____\r\nСоздать класс\r\nclass SomeClass {\r\n\r\n}\r\nдобавить в него поля и методы\r\nОдин метод должен выводить внутренние значения, второй менять\r\nВ конструкторе задать значения свойств\r\nдобавить в класс свойства хранящие название модуля и версию (отсчёт с 0.1)\r\n\r\nсоздать замыкание над классом для синглтона\r\nlet someObj = (function() {\r\nclass SomeClass {\r\n\r\n}\r\nreturn new SomeClass();\r\n})();\r\n\r\nНаписать класс методы которого позволяют получить\r\nмассив данных простых объектов с полем type и name\r\nодну запись из массива по переданному в метод параметру type\r\n\r\nреализовать на них: build enviroment fraction unit item furniture transport\r\nПродемонстрировать работу методов получения объектов.', '', 1, 23, '2026-06-18 09:35:43'),
(29, 'Тайловый редактор\r\n\r\nЦель\r\nСоздать тайловый редактор с возможностью превратить его в редактор территорий, города или дизайна помещения.\r\n\r\nПлан\r\n1 нед\r\nсоздать архитектуру, добавить bootstrap\r\nРазработать модули типовые\r\nbuild\r\nenviroment\r\nfraction\r\nunit\r\nфункционал объединить в main.js\r\n\r\n2 нед\r\nsystem - загрузка данных с сервера\r\nscene\r\nmap\r\n\r\n3 нед\r\nсоздание модуля\r\nmap_editor\r\nслои\r\nдеструктурирование смежных тайлов\r\nпрямая и изометрическая проекция\r\n\r\n\r\n4 нед\r\nengine - движок логики действий пользователя\r\n\r\n5 нед\r\nmap_editor\r\nредактор помещений интерьеров\r\nредактор города и логистики\r\nредактор стратегии', '', 1, 24, '2026-06-18 09:35:43'),
(30, 'Задача\r\n\r\nПри разработке нужно вести дневник версий модулей.\r\nНаписать редактор позволяющий создавать карты сцены с разной местностью,\r\nи размещением на ней статичных объектов.\r\nСозданные карты должны сохраняться в файл (или набор файлов)\r\n\r\nРедактор должен считывать созданные карты.\r\nРедактор должен переключаться между режимами прямой и изометрической проекции.\r\n\r\nУ каждого модуля должны быть свойства: название и версия.\r\nу каждого модуля должен быть метод info - возвращающий строку названия + версии\r\n\r\nДанные должны грузиться с сервера из БД\r\nМодуль должен возвращать прототип модуля из которого можно получить прототипы объектов за которые отвечает модуль. (Здание, ландшафт, предмет, мебель)\r\n\r\nМетоды типового модуля (type_className):\r\nПолучить список всех типов объектов, которые порождаются классом\r\nПолучить прототип объекта по указанному типу(ключу)\r\nСоздать объект этого класса\r\nПолучить нередактируемую копию объекта\r\nПолучить изображение всех объектов (при необходимости)\r\nПолучить изображение отдельного объекта (при необходимости)\r\nЕсли объекты могут объединятся в стек - метод сортировки объектов в стеке.', '', 1, 24, '2026-06-18 09:35:43'),
(31, 'Примеры использования\r\n\r\nОбращаясь к модулю - мы получаем либо список возможных типов объектов, либо прототип конкретного объекта и возможность обратиться к его методам и свойствам,\r\nчтобы затем использовать эти прототипы в фабриках объектов, порождающих массивы объектов из этих прототипов.\r\n\r\nbuildProto.getAllTypes().then(...);\r\nloadedProto = await buildProto.getAllTypes();\r\nunitProto.getImage();\r\nunitProto.getUnit(type).moveBonus;\r\ntypeLand = enviromentType(type);', '', 1, 24, '2026-06-18 09:35:43'),
(32, '1я неделя\r\n\r\nосновы js теория\r\njs - функции и лямда-функции, объекты\r\nтипы данных, работа с функциями', '', 1, 24, '2026-06-18 09:35:43'),
(33, 'Первые шаги:\r\n0.01\r\nсоздать файловую структуру проекта. (каталог проекта + что описано ниже)\r\nсоздать файлы документации проекта: описание и версии модулей.\r\nСоздать основной файл логики приложения: js/main.js\r\nсоздать файл основных стилей css/main.css\r\n\r\n0.02\r\nсоздать файл основной разметки приложения: index.html\r\nопределить в нём\r\nЯзыковую локализацию.\r\nМетаданные: кодировку, viewport, title\r\nПодключить стилевой файл main.css\r\nРазместить основной контейнер в body\r\n\r\n0.03\r\nсоздать js файлы системных модулей: экран сцена камера\r\nподключить js файлы с аттрибутом defer в index.html\r\nмодуль screen 0.3\r\nмодуль scene 0.1\r\ncamera 0.1\r\n\r\n0.04\r\nОтобразить сетку мира на экране.\r\nscreen 0.4\r\ncamera 0.2\r\n\r\n0.05\r\nCоздать мини-карту.\r\nотобразить камеры на миникарте.\r\nmap 0.1\r\ncamera 0.3\r\n\r\n0.06\r\nвынести enviromentType в отдельный модуль.\r\nсобытие клика по карте - перемещение камеры.\r\nПереключатель управления камерами.\r\nПодключить стили bootstrap.\r\nУвеличить количество enviroment_type.\r\nenviroment_type 0.1\r\nscene 0.2\r\nmap 0.2\r\ncamera 0.4\r\n\r\n0.07\r\nРедактирование островов.\r\nОтображать картинки тайлов.\r\nпостроение береговой линии.\r\nscene 0.3\r\nscreen 0.5\r\n\r\n0.08\r\nИзменить отображение тайла, строить из 4х спрайтов.\r\nСкругление тайлов воды, равнины, леса, болота.\r\nПостроение меню редактирования из списка enviroment_type.\r\nавтоматическое достраивание переходных тайлов.\r\nenviroment_type 0.3\r\nscene 0.4\r\nscreen 0.6', '', 1, 24, '2026-06-18 09:35:43'),
(34, 'По модулям:\r\n\r\nscene 0.4\r\n\r\n0.1\r\nсоздать файл scene.js - файл модуля.\r\nПодключить файл в html.\r\nсоздать замыкание: структуру модуля.\r\nСоздать внутренние параметры: ширина высота, слои природный и строений.\r\n\r\n0.2\r\nСоздать конструктор.\r\nЗадать размеры по умолчанию.\r\nсоздать геттер и сеттер размеров.\r\nВернуть объект сцены.\r\nЗаполнить ячейками по умолчанию.\r\n\r\n0.3\r\nРедактирование.\r\nАвтоматическое построение береговой линии.\r\nСкругление тайлов воды, равнины, леса, болота.\r\nавтоматическое достраивание переходных тайлов.\r\n\r\n0.4 Достраивание переходных тайлов', '', 1, 24, '2026-06-18 09:35:43'),
(35, 'camera 0.4\r\n\r\n4 Камера.\r\n0.1\r\nсоздать файл camera.js - файл модуля.\r\nПодключить файл в html.\r\nсоздать замыкание: структуру модуля.\r\nСоздать внутренние параметры: цвет, координаты, количество захваченных ячеек сцены.\r\nСоздать конструктор.\r\nЗадать размеры по умолчанию.\r\nВернуть объект камеры.\r\n\r\n0.2\r\nПолучить текущий снимок. (вернуть параметры камеры)\r\nПередвинуть камеру.\r\n\r\n0.3\r\nРазделить получение параметров и снимка.\r\nПолучить снимок из переданной матрицы.\r\n\r\n0.4\r\nПереключатели активности камер.', '', 1, 24, '2026-06-18 09:35:43'),
(36, 'Экран. screen 0.6\r\nСоздать screen.js - файл модуля.\r\nПодключить файл в html.\r\nсоздать замыкание: структуру модуля.\r\nСоздать внутренние параметры: ширина высота, размер ячейки,\r\nпараметры: количество ячеек по ширине и высоте\r\n\r\n0.2\r\nсоздать конструктор.\r\nвычислить размеры экрана.\r\nсоздать геттер и сеттер размеров экрана.\r\nВернуть объект экрана.\r\n\r\n0.3\r\nОпция: селектор блока.\r\nМетоды: Поиск блока по селектору.\r\nСоздание холстов.\r\nИзменение холстов.\r\nперекрыть канвасы через css.\r\n\r\n0.4\r\nСоздать холсты.\r\nОтобразить содержимое ячейки.\r\nОтобразить весь холст.\r\nЗадать типы поверхностей.\r\nЗадать окрас в зависимости от типа поверхности.\r\n\r\n0.5\r\nвывести спрайтами.\r\nожидание подгрузки спрайта перед рисовкой.\r\nКоординаты клика.\r\nКоординаты преобразовать в координаты ячейки.\r\n\r\n0.6\r\nТайл строится по 4м спрайтам.', '', 1, 24, '2026-06-18 09:35:43'),
(37, 'map 0.2\r\n3 Мини карта. map\r\n0.1\r\nсоздать файл map.js - файл модуля.\r\nПодключить файл в html.\r\nсоздать замыкание: структуру модуля.\r\nСоздать внутренние параметры: .\r\nСоздать конструктор.\r\nВернуть объект карты.\r\nполучить данные сцены и построить по ним канву.\r\n\r\n0.2\r\nотобразить рамки камер', '', 1, 24, '2026-06-18 09:35:43'),
(38, 'type_enviroment 0.3\r\n0.1\r\nСоздать файл enviroment_type.js\r\nПодключить файл в html.\r\nСоздать модуль\r\nДобавлены территории: море равнина лес холм болото гора\r\n\r\n0.2\r\nДобавлены территории: река побережье.\r\n\r\n0.3\r\nСкругление тайлов воды, равнины, леса, болота с помощью changeSet.', '', 1, 24, '2026-06-18 09:35:43'),
(39, 'создание файловой архитектуры проекта\r\nу меню - ссылки на районы города ижевска\r\n- индексный файл - регионы Удмуртии + крупные города(Ижевск, Глазов, Воткинск, Сарапул)\r\n- файлы списков: районы города, жк района, дома в жк, квартиры в доме\r\n- ссылка с глазова должна вести на\r\nhttps://www.google.com/maps/d/viewer?mid=1t-Q1W0rzFtp8piO3jZXEpEERAHk&ll=58.14269898006185%2C52.65371688761692&z=15\r\n- файл детального просмотра дома\r\n- файл ядра - подключения к БД\r\n- страница личного кабинета(квартиры) пользователя с архивом всех заказов и их статусом\r\n- страница кабинета(квартиры) должна быть доступна только авторизоавнным пользователям, неавторизованных перебрасывать на страницу авторизации\r\n\r\n- создать каталоги: (см магазины)\r\nотличия в разделах request и admin\r\nновости, заказы и баннеры - не нужно\r\nдобавить:\r\nрайоны, ЖК - аналог категорий для домов, квартиры, услуги\r\nструктура html документа по блокам\r\n- Создание шаблона страниц(см магазины)\r\n- Внутренние блоки обёртки content или wrapper\r\n- - Контейнеры на flex стилях', '', 1, 19, '2026-06-18 09:35:43'),
(40, '2я неделя\r\n\r\nСделать доступными неавторизованному пользователю публичные модули\r\n\r\nДобавить сайту форум, создав модуль forum\r\nмодуль в контроллере должен содержать методы: init, add_reply, edit_reply,\r\nadd_category, edit_category, category\r\nв init должна быть выборка категорий и вывод их на рендер\r\nдолжны присутствовать представления: \r\n - списка категорий, ответов внутри категории с пагинатором, форма категории, форма ответа.\r\n\r\nРазобраться почему не работает кнопка добавления товара в модуле /management/. Описать причину поломки и способ её решения. Починить функционал добаления товаров.\r\nДобавить для примера по 1 товару в каждый раздел.\r\nПодумать над улучшением удобства добавления товаров для авторизованных пользователей.', '', 1, 18, '2026-06-18 09:35:43'),
(41, '2я неделя\r\n\r\nПрикрепить в шапку логотип проекта.\r\nДобавить квартире статус перечисляемого типа: ремонт, сдаётся, жилая.\r\nДобавить квартире свойство: номер авто владельца - не отображать публично.\r\nНайти макет сайта посвящённого строительству, взять оттуда разметку и стили - применить к проекту, там где это уместно.\r\n\r\nсделать страницу вывода домов в квартале\r\n- небольшими изображениями домов сверху, либо схемы\r\nвывести на всех основных страницах информацию из БД\r\n\r\nСделать формы регистрации и авторизации, \r\nВёрстку форм прикрепления владельца к квартире, добавления товара, добавления услуги.\r\nНаписать обработчики форм.\r\n\r\nДобавить роли: пользователь, член совета дома, менеджер магазина, администратор.\r\nСверстать страницу развёртки дома:\r\n- крупное фото, план и прозрачная сетка квартир на фоне фото, при наведении на дом, развёртку сделать менее прозрачной более яркой.\r\nВ БД должны быть таблицы товаров, предоставляемые и необходимые услуги - это 2 таблицы\r\nпривязываемые к квартире. Содержат id title value dimension price description flat_id image', '', 1, 19, '2026-06-18 09:35:43'),
(42, '2 неделя Вёрстка\r\n\r\n- Создание блоков контента\r\n- Визуальная стилизация блоков\r\n- Наполнение страниц блоками информации\r\n- Создание форм\r\n- - категорий, товаров, новостей, баннеров\r\n- Кнопки покупки\r\n- Корзина с товарами', '', 1, 21, '2026-06-18 09:35:43'),
(43, '2я неделя\r\n\r\nЗамыкание контура по экранным координатам при клике в  заданной дельта окрестности от первой точки - завершение ввода контура.\r\nправый клик по точке - удаление точки.\r\n\r\nстек действий - действие представлять как координату тип действия, объект над которым выполнено действие.\r\n\r\nотмена ctrl+z - отменить последнее действие\r\nзамыкание по экранным координатам при заданном дельта\r\nenter - замкнуть контур и сохранить css контур\r\nотобразить без карты-подложки\r\nonfocus - подсветить контур\r\n\r\nперетаскивание и масштабирование - пересчёт видимых точек\r\nизменить рисовку на контурном слое после перемещений.', '', 1, 22, '2026-06-18 09:35:43'),
(44, '2я неделя\r\n\r\nсхема работы приложения\r\nмодуль данных - модуль фабрики - модуль контейнера - модуль навигации - модуль вывода\r\nотвечают за\r\nчто можно создавать - как создавать - где хранить созданное - поиск в хранилище - визуальное или детальное представление объекта пользователю\r\n\r\nПримеры цепочек:\r\n\r\nМодуль территорий - редактор - сцена - карта+камера - экран\r\n\r\nМодуль юнитов - - -- здание - -- сцена - карта+камера - экран\r\n\r\nМодуль предметов - -здание - -- ящик - экран - - - - - - - окно инвентаря\r\n\r\nРеализовать в дополнеие к модулям данных\r\n\r\nмодуль фабрики:\r\n - интерфейс редактора - отображает вне экрана список всех элементов которые может создать,\r\n - возможность выбрать и запомнить активный элемента\r\n - при клике на экране создаёт конкретный экземпляр объекта с уникальными свойствами по определённым правилам, например генерация изображения тайла из спрайтов, добавляет некоторые значения по-умолчанию, которых нет в модуле исходных данных\r\n\r\nмодуль контейнера\r\n - сцену - это просто матрица на которую можно разместить созданный экземпляр объекта\r\n \r\nмодуль вывода\r\n - экран - состоящий из перекрывающих друг друга слоёв canvas, разбитого на тайлы с заданной высотой и шириной (пусть отображает пока произвольную часть сцены)\r\n\r\nСистемный модуль позволяющий асинхронно: \r\n - отправить данные на сервер и получить данные с сервера\r\n - сохранить данные в файл и прочитать данные из файла\r\n - данный модуль не занимается интерпретацией данных, передаёт их как сырые данные.', '', 1, 23, '2026-06-18 09:35:43'),
(45, '.', '', 1, 24, '2026-06-18 09:35:43'),
(46, '.', '', 1, 24, '2026-06-18 09:35:43'),
(47, '0.09\r\nСохранение и загрузка островов.\r\nscene 0.5\r\n\r\n0.5\r\nЗагрузка и сохранение карт\r\nпока просто вывод в текстовое поле кодированного представления карты.\r\nзагрузка именно из файла через инпут.', '', 1, 24, '2026-06-18 09:35:43'),
(48, '2я неделя\r\n\r\nРеализовать модуль описывающий типы возможных территорий. Описание можно посмотреть тут:\r\nhttp://www.warlords1.ru/illuria.htm\r\nспрайты скидывал ранее.\r\n\r\nРеализовать меню выбора территорий которые размещаем.\r\n\r\nРеализовать сцену на которой размещаем территории, миникарту сцены, камеру для просмотра локации и экран отображающий те территории, на которые указывает камера.\r\n\r\nПри клике на экран:\r\nдолжен висеть обработчик события получающий координаты события. Координаты пересчитать в координаты сцены - поставить на это место выбранную в меню территорию.\r\nТут же обновить состояние экрана, чтобы увидеть размещённую территорию.\r\n\r\nНе смешивать код в одну кучу. Разделить его по логически изолированным модулям. Один модуль может внутри кода обращаться к коду другого, так будто он является библиотекой.', '', 1, 24, '2026-06-18 09:35:43'),
(49, 'План системного модуля system. \r\nЭто только план, не готовый код, вы можете сделать архитектуру иначе\r\n\r\nцель модуля: создавать произвольные меню, взаимодействовать с сервером, работать с файлами, уметь возвращать информацию о текущем приложении, создавать паузу выполнения, распознавать нажатые на клавиатуре клавиши.\r\n\r\nSystem(options) - конструктор\r\nsystem.info() - информация о самом модуле\r\n// меню\r\nMenu(name) - конструктор меню\r\nsystem.menu.addElement(href, title, icon, addClass, target) - добавить пункт в меню\r\nsystem.menu.show(name) - отобразить меню\r\n// сервер\r\nsystem.request(url, action, data = {}) - Отправить на сервер запрос и дождаться ответа\r\nsystem.objectJoin(obj, delimitterKeyValue = \'=\', delimitterPair = \'&\') - вспомогательный метод преобразования одноуровнего объекта в строку\r\n// файловая система\r\nsystem.createFile(name, code) - создать файл и положить в него код\r\n// приложение\r\nsystem.getWidth() - получить ширину экрана приложения\r\nsystem.pause(miliseconds) - создать паузу выполнения\r\nsystem.totalInfo - информация обо всех использованных модулях приложения\r\nsystem.getChar(event) - получение кода нажатой клавиши\r\nsystem.adaptive(width) - адаптация приложения под размер экрана\r\n// обработчики событий (пишутся вне модуля)\r\nнажатие на сохранение в файл использует system.createFile(\'map\', htmlText);\r\nнажатие загрузки из файла\r\nфайл загрузился\r\nданные из файла прочитаны\r\n\r\n// примеры использования:\r\nbeginBuildLocal = await system.serverRequest(\'build\', \'loadstate\');\r\nsystem.serverRequest(\'build\', \'delete\', {id}).then(\r\n            result => buildsType = JSON.parse(result),\r\n            error => console.log(error)\r\n        );\r\nsystem.serverRequest(\'build\', \'edit\', data).then(\r\n            result => {\r\n                // console.log(result);\r\n            },\r\n            error => console.log(error)\r\n        );\r\nwhile (scene.getLoadedCounts()) await system.pause(0);\r\nmessage = await system.serverRequest(\'army\', \'blessed\', {coord: focusedSquad});\r\nsystem.serverRequest(\'control_list\', \'set_ready\')\r\n        .then(data => {\r\n            if (data == \'yes\') {\r\n                console.log(\'Режим готовности\');\r\n            } else if (data == \'no\') {\r\n                console.log(\'Не передана доска\');\r\n            }\r\n        })\r\nsystem.serverRequest(\'life\', \'world\');\r\nsystem.serverRequest(\'life\', \'current\');\r\nsystem.serverRequest(\'life\', \'endturn\', {fraction: application.fraction}).then(\r\n            data => self.toAwait()\r\n        );', '', 1, 23, '2026-06-18 09:35:43'),
(50, 'Асинхронное и синхронное выполнение функций\r\n\r\nasync function f() {\r\n\r\n  let promise = new Promise((resolve, reject) => {\r\n    setTimeout(() => resolve(\"готово!\"), 3000)\r\n  });\r\n  \r\n  console.log(\'начало выполнения\');\r\n\r\n  let result = await promise; // будет ждать, пока промис не выполнится (*)\r\n\r\n  return result; // \"готово!\"\r\n}\r\n\r\nf().then(text => console.log(\'после функции \' + text));\r\n\r\nconsole.log(\'последняя команда\');', '', 1, 23, '2026-06-18 09:35:43'),
(51, '3 неделя\r\n\r\nСоздание форума продолжение. Папка /module/forum/\r\ncontroller\r\nview\r\nform.view\r\n\r\n-------------\r\nсоздать новый шаблон и перенести туда вёрстку от проекта ЖК\r\nсоздать модуль выводящий страницу с районами республики\r\n\r\nсоздать модуль ЛК пользователя со стилевыми настройками.\r\nНастройки хранить в таблице settings (color, border-radius, padding, text-size)\r\nПрименить настройки через стилевые классы body_style_styleName и styled_list styled_element\r\nпрописать разные варианты стилей для селекторов вида \'.body_style_styleName .styled_element\'\r\nменяющие общие характеристики элементов документа - цвет плашек, скругление углов, отступы, размер текста.\r\nПри выводе шаблона подставлять данные стилевые классы в body или обёртку с классом \'wrapper\'\r\nпеределать одну из страниц для демонстрации работы стилевых настроек пользователя', '', 1, 18, '2026-06-18 09:35:43'),
(52, '3 неделя\r\n\r\nСверстать страницу развёртки дома:\r\n- крупное фото, план и прозрачная сетка квартир на фоне фото, при наведении на дом, развёртку сделать менее прозрачной более яркой.\r\nНа страницу развёртки дома по параметру home_id вывести данные дома из БД (крупное фото дома, поэтажный план, в сетку квартир вывести данные из БД)\r\n\r\nСделать форму и её обработчик - позволяющие администраторы добавлять районы к городу, ЖК к району и дома к ЖК\r\nСоздайте 3 реальных жилых комплекса (пока без привязки к карте, но с привязкой к районам)\r\n\r\nСтраница Ижевска с выводом списка районов из базы данных.\r\n\r\nНаписать обработчик одобрения списка заявок привязки пользователей к квартирам.\r\nСтраница с формой редактирования квартиры - заполняет пользователь, и обработчик этой формы.\r\nВозможность разместить: 3 товара, услугу, потребность - товар или услуга.\r\nВозможность просмотреть список товаров и услуг дома должна быть только у зарегистрированных пользователей из того же жилого комплекса.', '', 1, 19, '2026-06-18 09:35:43'),
(53, '3 неделя\r\n\r\nВывод информации с бэкенда\r\n- Вывод списковой информации (категории, товары категории, заказы)\r\n- Вывод детальной информации (товар, заказ, личный кабинет)\r\n- скрипт создания корзины\r\n- добавление товара в корзину\r\n- скрипт перевода корзины в заказ\r\n\r\n------ подробнее ------\r\nВыборка из БД \r\n- подготовка SELECT запроса\r\n- выполнение SELECT запроса\r\nразбор результата выборки. Через fetch или  fetchAll\r\n- Вывести циклом foreach списковую информацию\r\n- Вывести через условные операторы детальную информацию\r\n- сформировать селекты(<select>) для форм\r\n- наполнить формы редактирования\r\nДобавление фильтров\r\nСоздание пагинатора (бесконечного)', '', 1, 21, '2026-06-18 09:35:43'),
(54, '3 неделя\r\n\r\nполучить масштаб и координаты - состояние карты подложки\r\n\r\nперетаскивание и масштабирование - пересчёт видимых точек\r\nизменить рисовку на контурном слое после перемещений.\r\n\r\nформировать path из созданного набора точек\r\nобратное преобразование - path  в набор точек на карте\r\nсохранять path в файл\r\nзагружать path из файла\r\n\r\ncntrl+click - взять ближайшую точку другого контура и добавить к текущему с отступом - перпендикулярным линии соединяющей две соседние точки относительно выделенной точки в контуре заимствования.\r\nвыделить контур. \r\nМеню дополнительных свойств объекта контура\r\nдействия над свойствами: переименовать, задать свойства.\r\ndel - удалить активный контур\r\nпересчёт координат географических и экранных - проверить на большом масштабе после перемещения карты по вертикали.\r\nСохранять и загружать контуры вместе со свойствами.', '', 1, 22, '2026-06-18 09:35:43'),
(55, '3 неделя (альтернативы)\r\n\r\nлибо развитие системного модуля в обработчик всех форм страницы (Данил Илья)\r\n\r\n----------\r\nлибо\r\nмодули\r\nunit transport - Илья\r\nbuild - Владислав\r\nenviroment item - Артур\r\nfraction furniture - Данил\r\n\r\nсцена - Артур\r\nкарта - Данил\r\nкамера - Олег и Максим\r\nэкран - Владислав, Илья\r\n\r\n----------\r\nлибо\r\nУчимся работать с javascript\r\nСоздание html с помощью javascript (table tr td): создание поля\r\nРабота с массивами данных: создание змейки\r\nРабота со свойствами и классами DOM: вывод статичной змейки\r\nработа с таймерами: движение и анимация\r\nРабота с условными операторами: замыкание границ поля\r\nНаписание обработчиков событий: работа с клавиатурой\r\nРабота с объектом event: получение кода нажатой клавиши\r\nВекторная логика движения: изменение направления змейки\r\nГенерация случайного положения с учётом препятствий: респаун еды\r\nСобираем игру змейку', '', 1, 23, '2026-06-18 09:35:43'),
(56, '3 неделя (альтернативы)\r\n\r\nсоздаём модуль камеры.\r\n- имеет координаты, цвет (для вывода рамки на миникарте) и масштаб (размер)\r\n- от масштаба зависит ширина и высота охвата\r\n- умеет возвращать своё внутреннее состояние\r\n- умеет перемещаться (менять координаты, с учётом границ сцены)\r\n- возможность изменить масштаб (в ограниченном диапазоне)\r\n- умеет получать данные из сцены: прямоугольник заданный её состоянием\r\n- возможность управлять с клавиатуры. (необходимость перерисовки экрана после движения)\r\n\r\n----------\r\nлибо\r\nУчимся работать с javascript\r\nСоздание html с помощью javascript (table tr td): создание поля\r\nРабота с массивами данных: создание змейки\r\nРабота со свойствами и классами DOM: вывод статичной змейки\r\nработа с таймерами: движение и анимация\r\nРабота с условными операторами: замыкание границ поля\r\nНаписание обработчиков событий: работа с клавиатурой\r\nРабота с объектом event: получение кода нажатой клавиши\r\nВекторная логика движения: изменение направления змейки\r\nГенерация случайного положения с учётом препятствий: респаун еды\r\nСобираем игру змейку', '', 1, 24, '2026-06-18 09:35:43'),
(57, '// переменные\r\n\r\nlet lastKeyCode = 37, // влево\r\nsnake, globalWidth, globalHeight, // задаём размер поля\r\ntimer = {id: null};\r\n\r\nfunction initialization(height, width) {\r\n    console.log(\'здесь создаём через вызов Table(w,h) и вставляем таблицу в документ и счётчик вызываем gameStart\');\r\n}\r\n\r\nfunction gameStart() {\r\n    console.log(\'инициализируем и респауним змейку и еду, затем устанавливаем таймер через setInterval у которого в качестве обработчика ставим самописный timeHandler возвращаем таймер\');\r\n}\r\n\r\nfunction gameOver() {\r\n}\r\n\r\nfunction Table(height, width) {\r\n    console.log(\'Эта функция создаёт и возвращает таблицу, обратите внимание на функции table.insertRow(-1); и row.insertCell(-1); чтобы не писать лишнего\');\r\n}\r\n\r\nfunction timeHandler() {\r\n    console.log(\'здесь только вызываем snake.step(globalWidth, globalHeight, lastKeyCode);\');\r\n}\r\n\r\nfunction getChar(event) {\r\n    console.log(\'распознаём код нажатой клавиши, всё кроме стрелок отбрасываем, результат записываем в lastKeyCode\');\r\n}\r\n\r\ncreateEat(length)\r\n\r\nfunction addCounter() {\r\n}\r\n\r\nfunction createCounter() {\r\n}\r\n\r\nfunction createSnake(x) {\r\n}\r\n\r\n// -------------- События --------------\r\ntimer.id = initialization(globalHeight, globalWidth);\r\naddEventListener(\"keydown\", getChar);', '', 1, 23, '2026-06-18 09:35:43'),
(58, '// класс змейки\r\nclass Snake {\r\n    // класс змейки должен содержать поля\r\n    direct: {x: -1, y: 0},\r\n    body: [];\r\n    \r\n    // и методы\r\n    getHead() // координаты головы\r\n    getLength() // длина змейки\r\n    respawn() // респауним созданную змейку\r\n    showSegment(i) // отобразить i ый сегмент? хорошо его инициализировать \r\n    // в = this.body.length - 1 так как обычно именно его будем отображать при анимации \r\n    // (исключение респаун)\r\n    newCoord() // вычисляем новые координаты = координаты головы + направление движения с учётом перехода границ поля\r\n    createSegment(x, y) // создаём новый сегмент по координатам\r\n    deleteTail()\r\n    getCeil(x, y) // хотя это метод поля, но можно реализовать как метод змейки\r\n    changeDirection(code) // меняем направление движения\r\n    eat(ceil) // съесть еду\r\n    step(width, height, lastKeyCode) // наиболее сложный метод, именно здесь применяем методы: смены направления, вычисления новых координат, проверки столкновения, съедание еды либо обычное движение, создаём и отображаем сегмент\r\n}', '', 1, 23, '2026-06-18 09:35:43');
INSERT INTO `reply` (`id`, `body`, `column2`, `author_id`, `replyable_id`, `datetime`) VALUES
(59, 'реализация методов по дням\r\n\r\nпн\r\nСоздание html с помощью javascript (table tr td): создание поля\r\nTable\r\ngetCeil(x, y)\r\nРабота с массивами данных: создание змейки\r\ncreateSnake\r\nсоздаём класс и объект змейки new Snake() с несколькими сегментами\r\n\r\ninitialization - наполняем постепенно в течении всех дней\r\ngameStart - наполняем постепенно\r\n\r\nвт\r\nРабота со свойствами и классами DOM: вывод статичной змейки\r\ngetHead()\r\ngetLength()\r\nrespawn()\r\nshowSegment(i)\r\nРабота с условными операторами: замыкание границ поля\r\nnewCoord()\r\nработа с таймерами: движение и анимация\r\ntimeHandler\r\ncreateSegment(x, y)\r\ndeleteTail()\r\nstep()\r\n\r\nср\r\nНаписание обработчиков событий: работа с клавиатурой\r\nРабота с объектом event: получение кода нажатой клавиши\r\ngetChar\r\n\r\nВекторная логика движения: изменение направления змейки\r\nchangeDirection(code)\r\n\r\nчт\r\nГенерация случайного положения с учётом препятствий: респаун еды\r\neat(ceil)\r\ncreateEat\r\n\r\nСобираем игру змейку\r\ngameOver\r\naddCounter\r\ncreateCounter', '', 1, 23, '2026-06-18 09:35:43'),
(60, '4я неделя\r\n\r\nпроверка модулей форума и настроек\r\n\r\nДобавить административный модуль редактирования модулей\r\n- модуль должен принадлежать к числу административных\r\n- должен позволять создавать новые модули и привязывать к ним таблицу\r\n- заносить данные о новом модуле в БД - устанавливать уровнь доступа к нему\r\n- в зависимости от уровня доступа модуля - создавать для него каталог в соответствующем каталоге.\r\n- В каталог модуля записывать файлы controller view\r\n- - с минимально необходимым функционалом для отображения информации из привязанной таблицы', '', 1, 18, '2026-06-18 09:35:43'),
(61, '4я неделя\r\n\r\nСверстать страницу дома\r\nСверстать Страницы редактирования жк и района ижевска\r\nСовету дома\r\nпредоставить доступ к просмотру и редактированию дополнительной информации: по квартирам и в целом по дому,\r\nвозможность создавать у дома дополнительные ветки форума.\r\nЛК - администратора для управления информацией по комплексам и районам.\r\nнапример загрузка картинок домов и т.д.\r\n- Создание js обработчиков для всех форм\r\n- добавление комментариев на форум для всех авторизованных пользователей, принадлежащих этому дому\r\nНаписать php обработчики всех форм', '', 1, 19, '2026-06-18 09:35:43'),
(62, '4я неделя\r\n\r\nдобавление товара в корзину\r\nпри нажатии на кнопку в корзину \r\nповесьте простой js-fetch с отправкой id выбранного товара на адрес файла\r\n/basket/add.php (файл создайте)\r\n в этом файле добавляйте пришедший id в $_SESSION[\'basket\'][$_POST[\'id\']] = 1\r\nесли там уже есть этот товар, увеличьте счётчик\r\n$_SESSION[\'basket\'][$_POST[\'id\']]++\r\n\r\nзатем считайте сколько у вас всего товаров лежит в сессии корзины и эхайте это число.\r\nполучив в ответ число, если оно больше 0, то рядом с надписью корзины добавляйте это число.\r\n\r\nНа странице самой корзины превратите массив id товаров циклом в строку, сделайте фильтр выборки товаров по этим id - и выведите их точно так же, как выводите на обычных своих страницах с товарами, только в компактные строки, 1 товар на строку и без картинок.\r\n\r\n\r\nскрипт перевода корзины в заказ\r\nПри нажатии заказать и заполнении полей заказчика и его телефона - переведите всю информацию из сессии корзины и формы заказчика в таблицу заказов со статусом формируется (formed).\r\nИ очистите сессию корзины:\r\n$_SESSION[\'basket\'] = array();\r\n\r\n\r\nСоздание пагинатора\r\nСоздание js обработчиков для всех форм \r\nсмотрите листинги любой 1 из: \r\n- обработчик авторизации https://q-pax.ru/blog/erid/it/back/sql/db_practice_3/\r\n- обработчик добавления записи https://q-pax.ru/blog/erid/it/back/sql/db_practice_4/\r\n- обработчик добавления пользователя https://q-pax.ru/blog/erid/it/back/sql/db_practice_6/\r\n\r\nсделать рабочими формы авторизации, регистрации\r\nдобавление товара в корзину\r\nизменение корзины\r\nоформление заказа\r\nдобавление комментариев\r\nдобавление и редактирование категорий товаров и самих товаров', '', 1, 21, '2026-06-18 09:35:43'),
(63, '4я неделя\r\n\r\nСобрать первичный вариант карты города и республики с использованием скрипта карты и path элементов\r\n+ название и описание\r\nenter - замкнуть контур и сохранить css контур\r\nвыделить контур переименовать, задать свойства\r\nперемещение подложки и контура\r\nвыделить группу контуров\r\nпостроить новый контур по внешним точкам группы контуров\r\nвнешние - пренадлежат 1 контуру\r\nлибо принадлежность к контурам, меньше количества соседних точек по всем контурам которым принадлежит', '', 1, 22, '2026-06-18 09:35:43'),
(64, '4я неделя\r\n\r\nsystem - должен сохранять и загружать файлы\r\nотправлять данные на сервер и обрабатывать ответ от сервера асинхронно\r\nнаписать модули\r\nscene - матрица территорий и расположенных на них объектов\r\nmap - пиксельное отображение сцены на канве с режимами объектов\r\ncamera\r\nscreen\r\n\r\nмодули\r\nunit transport - Илья\r\nbuild - Владислав\r\nenviroment item - Артур\r\nfraction furniture - Данил\r\n\r\nсцена - Артур\r\nкарта - Данил\r\nэкран - Владислав, Илья', '', 1, 23, '2026-06-18 09:35:43'),
(65, '4я неделя\r\n\r\nсоздаём модуль камеры.\r\n- имеет координаты, цвет (для вывода рамки на миникарте) и масштаб (размер)\r\n- от масштаба зависит ширина и высота охвата\r\n- умеет возвращать своё внутреннее состояние\r\n- умеет перемещаться (менять координаты, с учётом границ сцены)\r\n- возможность изменить масштаб (в ограниченном диапазоне)\r\n- умеет получать данные из сцены: прямоугольник заданный её состоянием\r\n- возможность управлять с клавиатуры. (необходимость перерисовки экрана после движения)', '', 1, 24, '2026-06-18 09:35:43'),
(66, '5я неделя\r\n\r\nсоздаём новый шаблон (копируем готовую вёрстку) и на него переносим один из магазинов\r\nОтладка и рефакторинг проекта\r\n\r\nПишем модуль-интерфейс административного добавления новых модулей по кнопке\r\n- модуль должен принадлежать к числу административных\r\n- должен позволять создавать новые модули и привязывать к ним таблицу\r\n- заносить данные о новом модуле в БД - устанавливать уровнь доступа к нему\r\n- В каталог модуля записывать файлы controller view\r\n- - с минимально необходимым функционалом для отображения информации из привязанной таблицы', '', 1, 18, '2026-06-18 09:35:43'),
(67, '5я неделя\r\n\r\nпроверить наличие страниц: домов, кварталов, микрорайонов, магазинов.\r\nДобавляем карты\r\nдобавляем на карты мвеу и 1с-Ижтиси\r\n\r\nЛК - администратора для управления информацией по комплексам и районам.\r\nнапример загрузка картинок домов и т.д.\r\n- Создание js обработчиков для всех форм\r\nphp обработчики всех форм\r\n\r\nветки форума закрепляются за объектами разных уровней: для всего микрорайона, для квартала, для дома.\r\nПо дому выводить дополнительную информацию - интегрально предоставляемые и требуемые услуги жильцов, список товаров.\r\n- Создание пагинатора для товаров и услуг.', '', 1, 19, '2026-06-18 09:35:43'),
(68, '5я неделя\r\n\r\nПротестировать работу корзины и заказов\r\nФормы администрирования категорий и товаров\r\nФронтенд обработка форм администрирования\r\nи администрирование - скрипты изменения записей в БД.\r\nдобавление и редактирование категорий товаров и самих товаров\r\nОтладка и рефакторинг проекта', '', 1, 21, '2026-06-18 09:35:43'),
(69, '5я неделя\r\n\r\nполучить масштаб и координаты - состояние карты подложки\r\n- пересчёт координат географических и экранных - проверить на большом масштабе после перемещения карты по вертикали\r\nзагрузка контуров из файла\r\ncntrl+click - взять ближайшую точку другого контура\r\n\r\nстраница редактирования контуров\r\nвыделить контур переименовать, задать свойства\r\ndel - удалить активный контур\r\nвыделить группу контуров\r\nпостроить новый контур по внешним точкам группы\r\nвнешние - пренадлежат 1 контуру\r\nлибо принадлежность к контурам меньше количества соседних точек по всем контурам которым принадлежит\r\n\r\nс помощью инструмента оцифровать карты районов удмуртии и районов Ижевска\r\nвывести результат на страницу с подключенными map.js и contur.js - содержащий path\'ы', '', 1, 22, '2026-06-18 09:35:43'),
(70, '5я неделя\r\n\r\nbuild_factory - Владислав\r\nдоработка scene - Артур\r\nscreen - Илья\r\nbuild_interface - Данил\r\ncamera - Олег\r\nmap_editor - Максим\r\n\r\nмодули\r\nscene - дописать функционал редактирования сцены, работы со зданиями и загрузки и сохранения в файл\r\nbuild_factory - хранилище зданий размещённых на сцене\r\ncamera - модуль камеры\r\nscreen - модуль экрана выводит картинки объектов сцены\r\nbuild_interface - строит интерфейс управления внутренними свойствами здания', '', 1, 23, '2026-06-18 09:35:43'),
(71, '5я неделя\r\n\r\ncamera - Олег\r\nmap_editor - Максим\r\n\r\nмодули.\r\nmap_editor - позволяет редактировать сцену, достраивать спрайты тайлов и отменять действия\r\ncamera - модуль камеры', '', 1, 24, '2026-06-18 09:35:43');
